const items = $input.all();
const results = [];

for (const item of items) {
  const prevItem = item.json;
  const originalData = $('循环量子位文章').item.json;

  if (prevItem.error) {
    console.log('HTTP请求失败，使用RSS描述:', prevItem.error);
    results.push({ json: { ...originalData, fullContent: originalData.contentSnippet || 'RSS描述(抓取失败)' }});
    continue;
  }

  let html = '';

  if (typeof prevItem === 'string') {
    html = prevItem;
  } else if (prevItem.data) {
    html = prevItem.data;
  } else if (prevItem.body) {
    html = prevItem.body;
  } else if (item.binary && item.binary.data) {
    html = Buffer.from(item.binary.data, 'base64').toString('utf-8');
  }

  if (!html || html.length < 100) {
    results.push({ json: { ...originalData, fullContent: originalData.contentSnippet || 'RSS描述' }});
    continue;
  }

  let title = originalData.title || '';
  const titleMatch = html.match(/<h1[^>]*>([^<]+)<\/h1>/i);
  if (titleMatch) {
    title = titleMatch[1].replace(/&#8211;/g, '-').replace(/&amp;/g, '&').trim();
  }

  let creator = originalData.creator || '';
  const creatorMatch = html.match(/<span[^>]*class="author"[^>]*>[\\s\\S]*?<a[^>]*rel="author"[^>]*>([^<]+)<\/a>/i);
  if (creatorMatch) {
    creator = creatorMatch[1].trim();
  }

  let text = html;
  text = text.replace(/<head[\\s\\S]*?<\/head>/gi, '');
  text = text.replace(/<script[\\s\\S]*?<\/script>/gi, '');
  text = text.replace(/<style[\\s\\S]*?<\/style>/gi, '');
  text = text.replace(/<!--[\\s\\S]*?-->/g, '');

  const articleStart = text.indexOf('<div class="article">');
  if (articleStart > -1) {
    text = text.substring(articleStart);
    const rightStart = text.indexOf('<div class="content_right">');
    if (rightStart > -1) {
      text = text.substring(0, rightStart);
    }
  }

  text = text.replace(/<[^>]+>/g, ' ');
  text = text.replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&#8211;/g, '-').replace(/&#8220;/g, '\\"').replace(/&#8221;/g, '\\"').replace(/&#\\d+;/g, '');
  text = text.replace(/\\s+/g, ' ').trim();

  let content = text.substring(0, 3000);
  if (!content || content.length < 50) {
    content = (originalData.contentSnippet || 'RSS描述').substring(0, 500);
  }

  results.push({ json: { ...originalData, title: title, creator: creator, fullContent: content }});
}

return results;

