// 按平台分组
const items = $input.all();
const grouped = {};

items.forEach(item => {
  const platform = item.json.platform;
  if (!grouped[platform]) {
    grouped[platform] = [];
  }
  grouped[platform].push(item.json);
});

// 转换为数组输出
const result = Object.keys(grouped).map(platform => ({
  json: {
    platform: platform,
    items: grouped[platform]
  }
}));

return result;

// 解析DeepSeek返回的Markdown
const response = $input.first().json;
const markdown = response.choices[0].message.content;

// 将Markdown转换为HTML
function markdownToHtml(md) {
  return md
    .replace(/^# (.+)$/gm, '<h1>$1</h1>')
    .replace(/^## (.+)$/gm, '<h2 class="platform-title">$1</h2>')
    .replace(/^### (.+)$/gm, '<h3>$1</h3>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\[(.+?)\]\((.+?)\)/g, '<a href="$2">$1</a>')
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    .replace(/^---$/gm, '<hr>')
    .replace(/\n\n/g, '</p><p>')
    .replace(/^(.+)$/gm, '<p>$1</p>');
}

