    newsData += `\n新闻 ${index + 1}:\n`;
    newsData += `标题: ${item.title}\n`;
    newsData += `链接: ${item.link}\n`;
    newsData += `内容: ${item.fullContent ? item.fullContent.substring(0, 500) : item.content}\n`;
